example.code:
variables {
  a429Word LBL_103 myWord = {msgChannel = 1};
}
on start {
  myWord.SSM_103 = 3;
  output (myWord); // start scheduling
}
on key '+' {
  myWord.SelAirspeed.phys += 22.5;
  output(myWord); // update
}
on key '-' {
  myWord.SelAirspeed.phys -= 22.5;
  output(myWord); // update
}
